        for field_match in re.finditer(
            rf"(?ms)^- (?P<field>{field_names})：(?P<value>.*?)(?=^- (?:{field_names})：|\Z)",
            match.group("body"),
        ):
            fields[field_match.group("field").strip()] = field_match.group("value").strip()
        return fields


