SLUG_LIKE_PATTERN = re.compile(r"^[A-Za-z0-9._/-]+$")
MAX_SUFFIX_LENGTH = 40
AMBIGUOUS_SINGLE_TOKEN_PURPOSES = {
    "help",
    "fix",
    "tmp",
    "temp",
